"""
    upload_read_set_part(part_number, part_source, payload, sequence_store_id, upload_id)
    upload_read_set_part(part_number, part_source, payload, sequence_store_id, upload_id, params::Dict{String,<:Any})

Uploads a specific part of a read set into a sequence store. When you a upload a read set
part with a part number that already exists, the new part replaces the existing one. This
operation returns a JSON formatted response containing a string identifier that is used to
confirm that parts are being added to the intended upload.

For more information, see [Direct upload to a sequence store](https://docs.aws.amazon.com/omics/latest/dev/synchronous-uploads.html)
in the *Amazon Web Services HealthOmics User Guide*.

# Arguments

- `part_number`: The number of the part being uploaded.
- `part_source`: The source file for an upload part.
- `payload`: The read set data to upload for a part.
- `sequence_store_id`: The Sequence Store ID used for the multipart upload.
- `upload_id`: The ID for the initiated multipart upload.
"""
function upload_read_set_part end

function upload_read_set_part(
    partNumber,
    partSource,
    payload,
    sequenceStoreId,
    uploadId;
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return omics(
        "PUT",
        "/sequencestore/$(sequenceStoreId)/upload/$(uploadId)/part",
        Dict{String,Any}(
            "partNumber" => partNumber, "partSource" => partSource, "payload" => payload
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function upload_read_set_part(
    partNumber,
    partSource,
    payload,
    sequenceStoreId,
    uploadId,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return omics(
        "PUT",
        "/sequencestore/$(sequenceStoreId)/upload/$(uploadId)/part",
        Dict{String,Any}(
            mergewith(
                _merge,
                Dict{String,Any}(
                    "partNumber" => partNumber,
                    "partSource" => partSource,
                    "payload" => payload,
                ),
                params,
            ),
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end
